Tras normalizar los strings (minúsculas, sin espacios), se construye un mapa de frecuencias para el primero y se decrementa con el segundo. Si todas las frecuencias quedan en cero, son anagramas. Alternativamente se pueden ordenar los caracteres y comparar.

function sonAnagramas(a: string, b: string): boolean {
  const normalizar = (s: string) => s.toLowerCase().replace(/\s/g, '');
  const s1 = normalizar(a);
  const s2 = normalizar(b);
  if (s1.length !== s2.length) return false;

  const conteo = new Map<string, number>();
  for (const c of s1) {
    conteo.set(c, (conteo.get(c) ?? 0) + 1);
  }
  for (const c of s2) {
    const actual = conteo.get(c);
    if (actual === undefined || actual === 0) return false;
    conteo.set(c, actual - 1);
  }
  return true;
}

