La solución óptima usa un hashmap para almacenar cada número y su índice mientras se recorre el array. Para cada elemento, se calcula su complemento (`target - num`) y se verifica si ya existe en el mapa. Si existe, se retornan los dos índices inmediatamente.

function twoSum(nums: number[], target: number): [number, number] {
  const visto = new Map<number, number>(); // valor -> índice
  for (let i = 0; i < nums.length; i++) {
    const complemento = target - nums[i];
    if (visto.has(complemento)) {
      return [visto.get(complemento)!, i];
    }
    visto.set(nums[i], i);
  }
  throw new Error('No se encontró solución');
}

