function mergeSorted(a: number[], b: number[]): number[] {
  const resultado: number[] = [];
  let i = 0, j = 0;
  while (i < a.length && j < b.length) {
    if (a[i] <= b[j]) {
      resultado.push(a[i++]);
    } else {
      resultado.push(b[j++]);
    }
  }
  while (i < a.length) resultado.push(a[i++]);
  while (j < b.length) resultado.push(b[j++]);
  return resultado;
}

