function aplanar<T>(arr: (T | (T | unknown[])[])[]): T[] {
  const resultado: T[] = [];
  for (const elemento of arr) {
    if (Array.isArray(elemento)) {
      resultado.push(...aplanar(elemento as (T | unknown[])[]));
    } else {
      resultado.push(elemento as T);
    }
  }
  return resultado;
}

