modelAnswer:
La solución usa un Map para acceso O(1) y una lista doblemente enlazada para mantener el orden LRU. La cabeza de la lista es el más reciente, la cola el menos reciente. Se usan nodos centinela para simplificar las operaciones de la lista.

class LRUCache {
  private capacidad: number;
  private mapa: Map<number, ListNode>;
  private cabeza: ListNode; // más reciente
  private cola: ListNode;   // menos reciente

  constructor(capacidad: number) {
    this.capacidad = capacidad;
    this.mapa = new Map();
    this.cabeza = new ListNode(0, 0);
    this.cola = new ListNode(0, 0);
    this.cabeza.siguiente = this.cola;
    this.cola.anterior = this.cabeza;
  }

  get(key: number): number {
    const nodo = this.mapa.get(key);
    if (!nodo) return -1;
    this.moverAlFrente(nodo);
    return nodo.val;
  }

  put(key: number, value: number): void {
    if (this.mapa.has(key)) {
      const nodo = this.mapa.get(key)!;
      nodo.val = value;
      this.moverAlFrente(nodo);
    } else {
      const nuevo = new ListNode(key, value);
      this.mapa.set(key, nuevo);
      this.agregarAlFrente(nuevo);
      if (this.mapa.size > this.capacidad) {
        const eliminado = this.eliminarCola();
        this.mapa.delete(eliminado.key);
      }
    }
  }

  private agregarAlFrente(nodo: ListNode): void {
    nodo.siguiente = this.cabeza.siguiente;
    nodo.anterior = this.cabeza;
    this.cabeza.siguiente!.anterior = nodo;
    this.cabeza.siguiente = nodo;
  }

  private eliminarNodo(nodo: ListNode): void {
    nodo.anterior!.siguiente = nodo.siguiente;
    nodo.siguiente!.anterior = nodo.anterior;
  }

  private moverAlFrente(nodo: ListNode): void {
    this.eliminarNodo(nodo);
    this.agregarAlFrente(nodo);
  }

  private eliminarCola(): ListNode {
    const nodo = this.cola.anterior!;
    this.eliminarNodo(nodo);
    return nodo;
  }
}

class ListNode {
  key: number; val: number;
  anterior: ListNode | null = null;
  siguiente: ListNode | null = null;
  constructor(key: number, val: number) {
    this.key = key; this.val = val;
  }
}

Complejidad temporal: O(1) para get y put.
Complejidad espacial: O(capacidad) — el Map y la lista almacenan como máximo `capacidad` elementos.

