La clave del hashmap es el string con sus caracteres ordenados alfabéticamente (su 'firma'). Todos los anagramas comparten la misma firma. Se itera el array, se calcula la firma de cada string y se agrupa en el mapa.

import java.util.*;

public List<List<String>> agruparAnagramas(String[] palabras) {
    Map<String, List<String>> grupos = new HashMap<>();
    for (String palabra : palabras) {
        char[] chars = palabra.toCharArray();
        Arrays.sort(chars);
        String firma = new String(chars);
        grupos.computeIfAbsent(firma, k -> new ArrayList<>()).add(palabra);
    }
    return new ArrayList<>(grupos.values());
}

