  isAllowed(clientId: string): boolean {
    const ahora = Date.now();
    const umbral = ahora - this.ventanaMs;

    if (!this.solicitudes.has(clientId)) {
      this.solicitudes.set(clientId, []);
    }

    const cola = this.solicitudes.get(clientId)!;
    // Eliminar timestamps fuera de la ventana
    while (cola.length > 0 && cola[0] <= umbral) {
      cola.shift();
    }

    if (cola.length < this.limite) {
      cola.push(ahora);
      return true;
    }
    return false;
  }

  // Limpiar entradas de clientes inactivos para evitar fugas de memoria
  purgar(): void {
