modelAnswer:
La clave es usar un tipo genérico `EventMap` que mapee nombres de eventos a sus payloads. Los métodos `on`, `emit` y `off` usan `K extends keyof EventMap` para que TypeScript infiera el tipo correcto del payload según el evento.

type Handler<T> = (payload: T) => void;

class EventBus<EventMap extends Record<string, unknown>> {
  private handlers: Map<keyof EventMap, Set<Handler<unknown>>>;

  constructor() {
    this.handlers = new Map();
  }

  on<K extends keyof EventMap>(evento: K, handler: Handler<EventMap[K]>): void {
    if (!this.handlers.has(evento)) {
      this.handlers.set(evento, new Set());
    }
    this.handlers.get(evento)!.add(handler as Handler<unknown>);
  }

  off<K extends keyof EventMap>(evento: K, handler: Handler<EventMap[K]>): void {
    this.handlers.get(evento)?.delete(handler as Handler<unknown>);
  }

  emit<K extends keyof EventMap>(evento: K, payload: EventMap[K]): void {
    this.handlers.get(evento)?.forEach(handler => handler(payload));
  }
}

// Ejemplo de uso con type-safety completa
type MisEventos = {
  'usuario:login': { userId: string; email: string };
  'pedido:creado': { pedidoId: number; total: number };
};

const bus = new EventBus<MisEventos>();
bus.on('usuario:login', ({ userId, email }) => {
