}

public class Codec {
    private static final String NULL_MARKER = "#";
    private static final String SEPARADOR = ",";

    public String serialize(TreeNode root) {
        StringBuilder sb = new StringBuilder();
        serializarAux(root, sb);
        return sb.toString();
    }

    private void serializarAux(TreeNode nodo, StringBuilder sb) {
        if (nodo == null) {
            sb.append(NULL_MARKER).append(SEPARADOR);
            return;
        }
        sb.append(nodo.val).append(SEPARADOR);
        serializarAux(nodo.left, sb);
        serializarAux(nodo.right, sb);
    }

    public TreeNode deserialize(String data) {
        Queue<String> tokens = new LinkedList<>(Arrays.asList(data.split(SEPARADOR)));
        return deserializarAux(tokens);
    }

    private TreeNode deserializarAux(Queue<String> tokens) {
        String token = tokens.poll();
        if (token == null || token.equals(NULL_MARKER)) return null;
        TreeNode nodo = new TreeNode(Integer.parseInt(token));
        nodo.left = deserializarAux(tokens);
        nodo.right = deserializarAux(tokens);
        return nodo;
    }
}

Complejidad temporal: O(n) para serialize y deserialize — se visita cada nodo exactamente una vez.
Complejidad espacial: O(n) para el string resultado y O(h) para el call stack de recursión, donde h es la altura del árbol (O(n) en el peor caso para árboles degenerados).

